const StageContent: React.FC<{
  currentStory: Story | null;
  areVotesRevealed: boolean;
  stats: { average: string | number; agreement: number; counts: Record<string, number> };
  isScrumMaster: boolean;
  onReveal: () => void;
  onReset: () => void;
  onFinalize: (val: string | number) => void;
}> = ({ currentStory, areVotesRevealed, stats, isScrumMaster, onReveal, onReset, onFinalize }) => {

  const [showManualEntry, setShowManualEntry] = useState(false);

  // Reset manual entry toggle when story changes or votes reset
  useEffect(() => {
    setShowManualEntry(false);
  }, [currentStory?.id, areVotesRevealed]);

  if (!currentStory) {
    return (
      <div className="flex flex-col items-center justify-center h-full text-slate-400 space-y-2 py-6">
        <div className="text-4xl">🃏</div>
        <h2 className="text-lg font-medium">Waiting for Story...</h2>
        {isScrumMaster && <p className="text-xs opacity-75">Select a story from the sidebar</p>}
      </div>
    );
  }

  if (areVotesRevealed) {
    // Calculate consensus (modes)
    const voteCounts = stats.counts;
    const maxVotes = Math.max(...Object.values(voteCounts), 0);
    const consensusValues = Object.entries(voteCounts)
        .filter(([_, count]) => count === maxVotes)
        .map(([val]) => val)
        .sort((a, b) => {
             const na = Number(a);
             const nb = Number(b);
             if (!isNaN(na) && !isNaN(nb)) return na - nb;
             return a.localeCompare(b);
        });

    // Helper for distribution bar sorting
    const sortedDistribution = Object.entries(voteCounts).sort((a, b) => {
        const na = Number(a[0]);
        const nb = Number(b[0]);
        if (!isNaN(na) && !isNaN(nb)) return na - nb;
        return a[0].localeCompare(b[0]);
    });

    return (
      <div className="flex flex-col items-center w-full animate-fade-in py-2 gap-4">

        <div className="flex flex-col md:flex-row items-center justify-center gap-6 w-full">
            {/* Consensus Display */}
            <div className="bg-slate-800/80 px-6 py-3 rounded-2xl border border-indigo-500/30 shadow-lg flex flex-col items-center min-w-[160px]">
                <div className="text-indigo-300 text-[10px] uppercase font-bold tracking-widest mb-1">Consensus</div>
                <div className="flex items-center gap-2">
                    {consensusValues.map((val, idx) => (
                        <div key={val} className="flex items-center">
                            <span className="text-5xl font-black text-white drop-shadow-sm">{val}</span>
                            {idx < consensusValues.length - 1 && <span className="text-xl text-slate-500 mx-1">&</span>}
                        </div>
                    ))}
                </div>
                <div className={`mt-1 text-[10px] font-bold px-2 py-0.5 rounded-full ${stats.agreement >= 80 ? 'bg-emerald-900/50 text-emerald-400' : 'bg-yellow-900/50 text-yellow-400'}`}>
                    {stats.agreement}% Agreement
                </div>
            </div>

            {/* Vote Distribution Bar */}
            <div className="w-full max-w-xs space-y-2">
                <div className="flex justify-between text-[10px] text-slate-400 uppercase font-bold">
                    <span>Distribution</span>
                    <span>{Object.values(currentStory.votes).length} Votes</span>
                </div>
                <div className="flex h-8 w-full rounded-lg overflow-hidden bg-slate-900 shadow-inner border border-slate-700">
                    {sortedDistribution.map(([val, count]) => {
                        const colors = ['bg-indigo-500', 'bg-purple-500', 'bg-pink-500', 'bg-rose-500', 'bg-orange-500', 'bg-amber-500'];
                        const colorIdx = (val.charCodeAt(0) + (val.length > 1 ? val.charCodeAt(1) : 0)) % colors.length;
                        const color = colors[colorIdx];
                        const total = Object.values(currentStory.votes).length;
                        const width = (count / total) * 100;

                        return (
                            <div 
                                key={val} 
                                className={`${color} h-full flex items-center justify-center text-xs font-bold text-white border-r border-slate-900/20 last:border-0 hover:brightness-110 transition-all`} 
                                style={{ width: `${width}%` }} 
                                title={`${val}: ${count} votes`}
                            >
                                {width > 8 && val}
                            </div>
                        );
                    })}
                </div>
            </div>
        </div>

        {isScrumMaster && (
          <div className="flex flex-wrap justify-center gap-2 items-center w-full mt-2">
            {consensusValues.map(val => (
                <Button 
                    key={val} 
                    onClick={() => onFinalize(val)}
                    className="bg-emerald-600 hover:bg-emerald-500 text-white shadow-lg shadow-emerald-900/20"
                >
                    Accept {val}
                </Button>
            ))}

            <Button variant="secondary" onClick={onReset} className="border-slate-600">
                Revote
            </Button>

            {/* Manual Override Toggle */}
            <div className="relative">
                <button 
                    onClick={() => setShowManualEntry(!showManualEntry)}
                    className="p-2 bg-slate-800 border border-slate-700 rounded-lg hover:bg-slate-700 transition-colors text-slate-400 hover:text-white"
                    title="More Options"
                >
                     <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 5v.01M12 12v.01M12 19v.01M12 6a1 1 0 110-2 1 1 0 010 2zm0 7a1 1 0 110-2 1 1 0 010 2zm0 7a1 1 0 110-2 1 1 0 010 2z"></path></svg>
                </button>

                {showManualEntry && (
                    <div className="absolute top-full mt-2 left-1/2 -translate-x-1/2 z-50 flex flex-wrap justify-center gap-1 p-3 bg-slate-800 rounded-xl border border-slate-600 shadow-xl w-64 animate-fade-in">
                        {POINTING_SCALE.map(pts => (
                            <button
                                key={pts}
                                onClick={() => onFinalize(pts)}
                                className={`
                                    w-8 h-8 rounded-lg text-xs font-bold transition-all border
                                    ${consensusValues.includes(String(pts))
                                        ? 'bg-indigo-600 border-indigo-400 text-white'
                                        : 'bg-slate-900 border-slate-700 text-slate-300 hover:bg-slate-700 hover:border-slate-500'}
                                `}
                            >
                                {pts}
                            </button>
                        ))}
                    </div>
                )}
            </div>
          </div>
        )}
      </div>
    );
  }

  // Voting In Progress
  return (
    <div className="flex flex-col items-center justify-center w-full h-full py-4 gap-4">
        <div className="text-center space-y-2 max-w-2xl px-4">
            <h3 className="text-sm font-bold text-indigo-400 uppercase tracking-widest">Voting on</h3>
            <p className="text-xl md:text-2xl font-bold text-white leading-relaxed">
                {currentStory.title}
            </p>
        </div>

        <div className="flex items-center gap-6 mt-2">
             <div className="flex flex-col items-center">
                 <div className="w-12 h-12 bg-slate-900 rounded-2xl border border-slate-700 flex items-center justify-center text-xl font-bold text-white shadow-inner">
                     {Object.keys(currentStory.votes).length}
                 </div>
                 <span className="text-[10px] text-slate-500 uppercase font-bold mt-1">Votes</span>
             </div>

             {isScrumMaster ? (
                <Button
                    size="lg"
                    onClick={onReveal}
                    disabled={Object.keys(currentStory.votes).length === 0}
                    className="shadow-lg shadow-indigo-500/20 px-8"
                >
                    Reveal Cards
                </Button>
             ) : (
                <div className="h-12 flex items-center px-6 bg-slate-800/50 rounded-xl border border-slate-700/50 animate-pulse">
                    <span className="text-sm font-medium text-slate-400">
                        {Object.keys(currentStory.votes).length > 0 ? "Waiting for reveal..." : "Cast your vote..."}
                    </span>
                </div>
             )}
        </div>
    </div>
  );
};


const PokerTable: React.FC<PokerTableProps> = ({
  users,
  currentStory,
  areVotesRevealed,
  onReveal,
  onNext,
  onNextStory,
  onReset,
  currentUserRole,
  timer,
  onStartTimer,
  onPauseTimer,
  onResetTimer,
  onAddMinutes,
  lastReaction,
  onReaction
}) => {
  const [showGameHub, setShowGameHub] = useState(false);
  const prevRevealed = useRef(areVotesRevealed);
  const isScrumMaster = currentUserRole === UserRole.SCRUM_MASTER;

  // --- Effects ---
  useEffect(() => {
    if (areVotesRevealed && !prevRevealed.current) {
      playSound.reveal();

      let isConsensus = false;
      if (currentStory && currentStory.votes) {
        const votes = Object.values(currentStory.votes).filter(v => v !== null);
        const uniqueVotes = new Set(votes.map(v => String(v)));
        if (votes.length > 0 && uniqueVotes.size === 1) {
          isConsensus = true;
        }
      }

      if (isConsensus) {
        confetti({
          particleCount: 150,
          spread: 70,
          origin: { y: 0.6 },
          colors: ['#6366f1', '#8b5cf6', '#ec4899']
        });
      }
    }
    prevRevealed.current = areVotesRevealed;
  }, [areVotesRevealed, currentStory]);

  // --- Memoized Stats ---
  const stats = useMemo(() => {
    if (!currentStory?.votes) return { average: 0, agreement: 0, counts: {} };

    const votes = Object.values(currentStory.votes).filter(v => v !== null && v !== '?' && v !== '☕');
    const numericVotes = votes.map(v => Number(v)).filter(n => !isNaN(n));

    const counts: Record<string, number> = {};
    Object.values(currentStory.votes).forEach(v => {
      if (v !== null) {
        const s = String(v);
        counts[s] = (counts[s] || 0) + 1;
      }
    });

    if (numericVotes.length === 0) return { average: 0, agreement: 0, counts };

    const sum = numericVotes.reduce((a, b) => a + b, 0);
    const avg = sum / numericVotes.length;

    const maxCount = Math.max(...Object.values(counts));
    const totalVotes = Object.values(currentStory.votes).filter(v => v !== null).length;
    const agreement = totalVotes ? Math.round((maxCount / totalVotes) * 100) : 0;

    return { average: avg.toFixed(1), agreement, counts };
  }, [currentStory?.votes]);

  const handleFinalize = (val: string | number) => {
    onNext(val);
  };

  const handleReaction = (emoji: string) => {
    if (emoji === WOW_EMOJI) playSound.wow();
    else playSound.reaction();
    onReaction(emoji);
  };

  return (
    <div className="flex-1 relative bg-[radial-gradient(ellipse_at_center,_var(--tw-gradient-stops))] from-slate-800 via-slate-900 to-slate-950 flex flex-col overflow-hidden">

      {/* Global Overlays */}
      <ReactionOverlay lastReaction={lastReaction} />
      {showGameHub && <GameHub onClose={() => setShowGameHub(false)} />}

      {/* Game Hub Toggle */}
      <button 
        onClick={() => setShowGameHub(true)}
        className="absolute z-40 bg-indigo-600 hover:bg-indigo-500 text-white rounded-full flex items-center justify-center shadow-lg transition-transform hover:rotate-12 hover:scale-110 top-4 right-4 w-10 h-10"
        title="Arcade Mode"
      >
        <span className="text-xl">🎮</span>
      </button>

      {/* 1. TOP BAR: Timer & Reactions */}
      <div className="flex justify-between items-start p-4 shrink-0 z-30">
          <Timer 
             timer={timer} 
             onStart={onStartTimer} 
             onPause={onPauseTimer} 
             onReset={onResetTimer} 
             onAddMinutes={onAddMinutes}
             canControl={isScrumMaster} 
          />
          <div className="mr-12"> {/* Margin right to avoid GameHub button */}
            <ReactionBar onReaction={handleReaction} />
          </div>
      </div>

      {/* 2. STAGE: Story Info & Results */}
      <div className="flex-shrink-0 w-full px-4 mb-2 z-20">
          <div className="w-full max-w-4xl mx-auto bg-slate-800/60 border border-slate-700/50 rounded-3xl p-6 shadow-2xl backdrop-blur-md relative overflow-hidden group transition-all duration-300 hover:border-slate-600/50">
             {/* Decorative shine */}
             <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-transparent via-indigo-500/50 to-transparent opacity-50"></div>

             <StageContent 
                currentStory={currentStory}
                areVotesRevealed={areVotesRevealed}
                stats={stats}
                isScrumMaster={isScrumMaster}
                onReveal={onReveal}
                onReset={onReset}
                onFinalize={handleFinalize}
             />
          </div>
      </div>

      {/* 3. FIELD: User Grid (Scrollable) */}
      <div className="flex-1 overflow-y-auto overflow-x-hidden w-full px-4 pb-32 scrollbar-hide z-10">
         <div className="flex flex-wrap justify-center content-start gap-4 md:gap-8 max-w-6xl mx-auto py-4">
             {users.map(user => {
                  const hasVoted = currentStory?.votes?.[user.id] !== undefined;
                  const voteValue = currentStory?.votes?.[user.id];

                  return (
                      <div key={user.id} className="flex flex-col items-center gap-3 relative group">
                          {/* Card Area */}
                          <div className={`
                             relative transition-all duration-300 transform
                             ${hasVoted ? 'translate-y-0 opacity-100' : 'translate-y-2 opacity-50 grayscale'}
                             ${!hasVoted && 'hover:translate-y-1 hover:opacity-75'}
                          `}>
                              {hasVoted ? (
                                  <Card 
                                    value={voteValue || ''} 
                                    faceDown={!areVotesRevealed}
                                    revealed={areVotesRevealed}
                                    size="md" // Always use MD size for uniformity
                                    theme={user.cardTheme}
                                  />
                              ) : (
                                  // Empty Slot Placeholder
                                  <div className="w-14 h-20 md:w-16 md:h-24 rounded-xl border-2 border-dashed border-slate-700 bg-slate-800/30 flex items-center justify-center">
                                      <span className="text-slate-600 text-xs">Waiting</span>
                                  </div>
                              )}
                          </div>

                          {/* Avatar & Name - Strictly BELOW the card */}
                          <div className="flex flex-col items-center gap-1 z-10">
                              <div className={`
                                  w-10 h-10 rounded-full border-2 flex items-center justify-center text-lg shadow-md transition-colors bg-slate-800
                                  ${user.isOnline ? 'border-slate-600 text-white' : 'border-slate-700 text-slate-500'}
                                  ${hasVoted ? 'border-indigo-500 shadow-[0_0_10px_rgba(99,102,241,0.3)]' : ''}
                              `}>
                                  {user.avatar}
                                  {user.role === UserRole.SCRUM_MASTER && (
                                      <div className="absolute -top-1 -right-1 bg-amber-500 text-[8px] p-0.5 rounded-full border border-slate-900">👑</div>
                                  )}
                              </div>
                              <span className="text-xs font-medium text-slate-400 bg-slate-900/80 px-2 py-0.5 rounded-full border border-slate-800 truncate max-w-[100px]">
                                  {user.name}
                              </span>
                          </div>
                      </div>
                  )
             })}
         </div>
      </div>
    </div>
  );
};

