import React, { useRef, useState, useEffect, useCallback } from 'react';
import { db } from '../firebaseConfig';
import { User } from '../types';

interface Point {
  x: number;
  y: number;
}

interface DrawPath {
  id: string;
  userId: string;
  color: string;
  width: number;
  points: Point[];
}

interface WhiteboardProps {
  currentUser: User;
  onClose: () => void;
}

const COLORS = [
  '#ffffff', // White
  '#ef4444', // Red
  '#f59e0b', // Amber
  '#10b981', // Emerald
  '#3b82f6', // Blue
  '#8b5cf6', // Violet
  '#ec4899', // Pink
];

const Whiteboard: React.FC<WhiteboardProps> = ({ currentUser, onClose }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const [isDrawing, setIsDrawing] = useState(false);
  const [color, setColor] = useState(COLORS[0]);
  const [width, setWidth] = useState(3);
  const [paths, setPaths] = useState<DrawPath[]>([]);

  // Room ID sanitation
  const roomId = currentUser.room.replace(/[^a-zA-Z0-9]/g, '_');

  // --- Firebase Sync ---

  // 1. Listen for incoming paths
  useEffect(() => {
    if (!db) return;
    const pathsRef = db.ref(`sessions/${roomId}/whiteboard/paths`);

    const handleValue = (snapshot: any) => {
      const val = snapshot.val();
      if (val) {
        const loadedPaths = Object.values(val) as DrawPath[];
        setPaths(loadedPaths);
      } else {
        setPaths([]);
      }
    };

    pathsRef.on('value', handleValue);
    return () => {
      pathsRef.off('value', handleValue);
    };
  }, [roomId]);

  // 2. Function to save a completed path
  const savePath = (newPath: DrawPath) => {
    if (!db) return;
    const newRef = db.ref(`sessions/${roomId}/whiteboard/paths`).push();
    newRef.set(newPath);
  };

  // 3. Function to clear board
  const clearBoard = () => {
    if (!db) return;
    if (window.confirm('Clear the whiteboard for everyone?')) {
      db.ref(`sessions/${roomId}/whiteboard/paths`).remove();
    }
  };

  // --- Canvas Logic ---

  // Resize handler
  useEffect(() => {
    const handleResize = () => {
      if (containerRef.current && canvasRef.current) {
        const { width, height } = containerRef.current.getBoundingClientRect();
        // Set actual canvas size to match display size for sharpness
        canvasRef.current.width = width;
        canvasRef.current.height = height;
        // Re-draw all paths after resize
        drawAllPaths();
      }
    };

    window.addEventListener('resize', handleResize);
    handleResize(); // Initial size

    return () => window.removeEventListener('resize', handleResize);
  }, [paths]); // Re-bind if paths change to ensure redraw uses latest data

  const drawAllPaths = useCallback(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    ctx.clearRect(0, 0, canvas.width, canvas.height);
    ctx.lineCap = 'round';
    ctx.lineJoin = 'round';

    paths.forEach(path => {
      if (path.points.length < 2) return;

      ctx.beginPath();
      ctx.strokeStyle = path.color;
      ctx.lineWidth = path.width;

      // Denormalize coordinates
      const startX = path.points[0].x * canvas.width;
      const startY = path.points[0].y * canvas.height;

      ctx.moveTo(startX, startY);

      for (let i = 1; i < path.points.length; i++) {
        const x = path.points[i].x * canvas.width;
        const y = path.points[i].y * canvas.height;
        ctx.lineTo(x, y);
      }
      ctx.stroke();
    });
  }, [paths]);

  // Trigger redraw whenever paths update
  useEffect(() => {
    drawAllPaths();
  }, [drawAllPaths]);

  // --- Interaction Handlers ---

  const currentPathRef = useRef<Point[]>([]);

  const getNormalizedPoint = (e: React.MouseEvent | React.TouchEvent | MouseEvent | TouchEvent) => {
    const canvas = canvasRef.current;
    if (!canvas) return { x: 0, y: 0 };

    const rect = canvas.getBoundingClientRect();
    let clientX, clientY;

    if ('touches' in e) {
      clientX = e.touches[0].clientX;
      clientY = e.touches[0].clientY;
    } else {
      clientX = (e as React.MouseEvent).clientX;
      clientY = (e as React.MouseEvent).clientY;
    }

    return {
      x: (clientX - rect.left) / rect.width,
      y: (clientY - rect.top) / rect.height
    };
  };

  const startDrawing = (e: React.MouseEvent | React.TouchEvent) => {
    setIsDrawing(true);
    const point = getNormalizedPoint(e);
    currentPathRef.current = [point];
  };

  const draw = (e: React.MouseEvent | React.TouchEvent) => {
    if (!isDrawing) return;
    e.preventDefault(); // Prevent scrolling on touch

    const point = getNormalizedPoint(e);
    currentPathRef.current.push(point);

    // Optimistic drawing (draw locally immediately)
    const canvas = canvasRef.current;
    const ctx = canvas?.getContext('2d');
    if (canvas && ctx && currentPathRef.current.length >= 2) {
       const points = currentPathRef.current;
       const lastPoint = points[points.length - 2];
       const newPoint = points[points.length - 1];

       ctx.beginPath();
       ctx.strokeStyle = color;
       ctx.lineWidth = width;
       ctx.lineCap = 'round';
       ctx.lineJoin = 'round';
       ctx.moveTo(lastPoint.x * canvas.width, lastPoint.y * canvas.height);
       ctx.lineTo(newPoint.x * canvas.width, newPoint.y * canvas.height);
       ctx.stroke();
    }
  };

  const stopDrawing = () => {
    if (!isDrawing) return;
    setIsDrawing(false);

    if (currentPathRef.current.length > 0) {
      const newPath: DrawPath = {
        id: crypto.randomUUID(),
        userId: currentUser.id,
        color,
        width,
        points: currentPathRef.current
      };
      savePath(newPath);
    }
    currentPathRef.current = [];
  };

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center bg-slate-900/90 backdrop-blur-sm animate-fade-in">
      <div className="relative w-full h-full md:w-[90vw] md:h-[85vh] bg-slate-800 rounded-xl shadow-2xl overflow-hidden border border-slate-700 flex flex-col">

        {/* Toolbar */}
        <div className="bg-slate-900 p-3 flex items-center justify-between border-b border-slate-700 shrink-0">
          <div className="flex items-center gap-4">
             <div className="flex items-center gap-2 bg-slate-800 p-1.5 rounded-lg border border-slate-700">
                <span className="text-xs text-slate-400 uppercase font-bold px-2">Color</span>
                {COLORS.map(c => (
                  <button
                    key={c}
                    onClick={() => setColor(c)}
                    className={`w-6 h-6 rounded-full transition-transform hover:scale-110 ${color === c ? 'ring-2 ring-white scale-110' : ''}`}
                    style={{ backgroundColor: c }}
                    title={c}
                  />
                ))}
             </div>

             <div className="flex items-center gap-2 bg-slate-800 p-1.5 rounded-lg border border-slate-700">
                 <span className="text-xs text-slate-400 uppercase font-bold px-2">Size</span>
                 {[2, 4, 8].map(s => (
                    <button
                      key={s}
                      onClick={() => setWidth(s)}
                      className={`rounded-full bg-slate-400 transition-all hover:bg-white ${width === s ? 'bg-white' : ''}`}
                      style={{ width: s * 3, height: s * 3 }}
                      title={`Brush size ${s}`}
                    />
                 ))}
             </div>

             <button 
                onClick={clearBoard}
                className="text-xs font-bold text-red-400 hover:text-white hover:bg-red-600 px-3 py-1.5 rounded-lg transition-colors border border-red-900/50 hover:border-red-500"
             >
                Clear Board
             </button>
          </div>

          <div className="flex items-center gap-2">
             <h3 className="hidden md:block text-slate-400 font-bold uppercase tracking-widest text-sm mr-4">Collaborative Board</h3>
             <button 
