import React, { useRef, useState, useEffect } from 'react';
import { User } from '../types';

interface WhiteboardProps {
  currentUser: User;
  onClose: () => void;
}

const Whiteboard: React.FC<WhiteboardProps> = ({ currentUser, onClose }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [isDrawing, setIsDrawing] = useState(false);
  const [color, setColor] = useState('#6366f1'); // Indigo-500
  const [lineWidth, setLineWidth] = useState(3);

  // Initialize canvas
  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    const parent = canvas.parentElement;
    if (parent) {
      canvas.width = parent.clientWidth;
      canvas.height = parent.clientHeight;
    }

    const ctx = canvas.getContext('2d');
    if (ctx) {
      ctx.lineCap = 'round';
      ctx.lineJoin = 'round';
      ctx.strokeStyle = color;
      ctx.lineWidth = lineWidth;
    }

    const handleResize = () => {
        if (parent) {
            // Simple resize handling: creates a temporary canvas to save drawing
            const tempCanvas = document.createElement('canvas');
            tempCanvas.width = canvas.width;
            tempCanvas.height = canvas.height;
            const tempCtx = tempCanvas.getContext('2d');
            tempCtx?.drawImage(canvas, 0, 0);

            canvas.width = parent.clientWidth;
            canvas.height = parent.clientHeight;
            ctx?.drawImage(tempCanvas, 0, 0);

            // Restore context props
            if (ctx) {
                ctx.lineCap = 'round';
                ctx.lineJoin = 'round';
                ctx.strokeStyle = color;
                ctx.lineWidth = lineWidth;
            }
        }
    };

    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  // Update context styles
  useEffect(() => {
      const canvas = canvasRef.current;
      if (!canvas) return;
      const ctx = canvas.getContext('2d');
      if (ctx) {
          ctx.strokeStyle = color;
          ctx.lineWidth = lineWidth;
      }
  }, [color, lineWidth]);

  const startDrawing = (e: React.MouseEvent | React.TouchEvent) => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    setIsDrawing(true);
    const { x, y } = getPos(e, canvas);
    ctx.beginPath();
    ctx.moveTo(x, y);
  };

  const draw = (e: React.MouseEvent | React.TouchEvent) => {
    if (!isDrawing) return;
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const { x, y } = getPos(e, canvas);
    ctx.lineTo(x, y);
    ctx.stroke();
  };

  const stopDrawing = () => {
    if (isDrawing) {
        setIsDrawing(false);
        const canvas = canvasRef.current;
        const ctx = canvas?.getContext('2d');
        ctx?.closePath();
    }
  };

  const getPos = (e: React.MouseEvent | React.TouchEvent, canvas: HTMLCanvasElement) => {
    const rect = canvas.getBoundingClientRect();
    let clientX, clientY;

    if ('touches' in e) {
        clientX = e.touches[0].clientX;
        clientY = e.touches[0].clientY;
    } else {
        clientX = (e as React.MouseEvent).clientX;
        clientY = (e as React.MouseEvent).clientY;
    }

    return {
      x: clientX - rect.left,
      y: clientY - rect.top
    };
  };

  const clearBoard = () => {
      const canvas = canvasRef.current;
      const ctx = canvas?.getContext('2d');
      if (canvas && ctx) {
          ctx.clearRect(0, 0, canvas.width, canvas.height);
      }
  };

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center bg-slate-900/95 backdrop-blur-sm p-4 animate-fade-in">
      <div className="flex flex-col w-full max-w-5xl h-[85vh] bg-slate-800 rounded-2xl border border-slate-700 shadow-2xl overflow-hidden relative">

        {/* Toolbar */}
        <div className="flex items-center justify-between p-4 bg-slate-900 border-b border-slate-700 z-10">
           <div className="flex items-center gap-4">
               <div className="flex items-center gap-2 text-white font-bold">
                   <span className="text-2xl">✏️</span>
                   <span className="hidden sm:inline">Whiteboard</span>
               </div>

               <div className="h-8 w-px bg-slate-700 mx-2"></div>

               <div className="flex items-center gap-2">
                   <input 
                     type="color" 
                     value={color} 
                     onChange={(e) => setColor(e.target.value)}
                     className="w-8 h-8 rounded cursor-pointer bg-transparent border border-slate-600 p-0.5"
                     title="Brush Color"
                   />

                   <div className="flex items-center gap-1 bg-slate-800 rounded-lg border border-slate-700 px-2 py-1">
                      <div className="w-1 h-1 rounded-full bg-slate-400"></div>
                      <input 
                        type="range" 
                        min="1" 
                        max="20" 
                        value={lineWidth} 
                        onChange={(e) => setLineWidth(parseInt(e.target.value))}
                        className="w-20 h-1 accent-indigo-500 bg-slate-600 rounded-lg appearance-none cursor-pointer"
                        title="Brush Size"
                      />
                      <div className="w-3 h-3 rounded-full bg-slate-400"></div>
                   </div>
